import { memo } from "react";
import type { BookDefinition } from "../../lib/library";
import { BOOK_CATEGORIES } from "../../lib/library";

const STATUS_LABEL: Record<BookDefinition["status"], string> = {
  bloqueado: "🔒 Bloqueado",
  conhecido: "📘 Conhecido",
  lido: "✅ Lido",
};

interface BookCardProps {
  book: BookDefinition;
  selected: boolean;
  onSelect: (id: string) => void;
}

// Sprint Library System — item da estante (BookShelf). Mostra o livro
// mesmo bloqueado (Etapa "Mostrar livros bloqueados") — só some o
// conteúdo real, nunca o livro inteiro.
export const BookCard = memo(function BookCard({ book, selected, onSelect }: BookCardProps) {
  const category = BOOK_CATEGORIES.find((c) => c.slug === book.category);
  return (
    <button
      type="button"
      className={`book-card${selected ? " book-card-selected" : ""}${book.locked ? " book-card-locked" : ""}`}
      onClick={() => onSelect(book.id)}
    >
      <span className="book-card-icon">{category?.icon ?? "📖"}</span>
      <span className="book-card-info">
        <strong className="book-card-title">{book.title}</strong>
        <span className="book-card-author">{book.author}</span>
        <span className="book-card-status">{STATUS_LABEL[book.status]}</span>
      </span>
    </button>
  );
});
