import { useState } from "react";
import type { BookDefinition } from "../../lib/library";
import { BookPage } from "./BookPage";

interface BookReaderProps {
  book: BookDefinition | null;
}

// Sprint Library System — painel direito do códice (Etapa "Interface:
// Livro direita. Como um códice."). Livro bloqueado nunca mostra o
// conteúdo (Etapa "Mostrar livros bloqueados"), só o aviso + a condição
// de desbloqueio (ainda sem lógica real, só o texto aceito).
//
// Reaproveita `key={book.id}` do componente pai (LibraryBuilding) para
// reiniciar a página atual sempre que o livro selecionado muda — sem
// precisar de um useEffect próprio.
export function BookReader({ book }: BookReaderProps) {
  const [pageIndex, setPageIndex] = useState(0);

  if (!book) {
    return (
      <div className="book-reader book-reader-empty">
        <p className="hint">Escolha um livro na estante ao lado.</p>
      </div>
    );
  }

  if (book.locked) {
    return (
      <div className="book-reader book-reader-locked">
        <h3 className="book-reader-title">{book.title}</h3>
        <span className="book-reader-author">{book.author}</span>
        <p className="book-reader-locked-message">🔒 Este livro ainda está bloqueado.</p>
        <p className="hint">Condição de desbloqueio: {book.unlockCondition}</p>
      </div>
    );
  }

  const totalPages = book.pages.length;
  const currentPage = book.pages[Math.min(pageIndex, totalPages - 1)];

  return (
    <div className="book-reader">
      <h3 className="book-reader-title">{book.title}</h3>
      <span className="book-reader-author">{book.author}</span>
      <p className="book-reader-description">{book.description}</p>

      <BookPage content={currentPage} pageNumber={pageIndex + 1} totalPages={totalPages} />

      <div className="book-reader-nav">
        <button type="button" onClick={() => setPageIndex((p) => Math.max(0, p - 1))} disabled={pageIndex === 0}>
          ← Página anterior
        </button>
        <button
          type="button"
          onClick={() => setPageIndex((p) => Math.min(totalPages - 1, p + 1))}
          disabled={pageIndex >= totalPages - 1}
        >
          Página seguinte →
        </button>
      </div>
    </div>
  );
}
