import { memo } from "react";
import type { BookCategory as BookCategorySlug } from "../../lib/library";
import { BOOK_CATEGORIES } from "../../lib/library";

interface BookCategoryProps {
  selected: BookCategorySlug | null;
  onSelect: (category: BookCategorySlug | null) => void;
}

// Sprint Library System — filtro por categoria (Etapa "Busca: Filtrar
// categoria"). "Todas" (null) sempre disponível ao lado das 10 categorias.
export const BookCategory = memo(function BookCategory({ selected, onSelect }: BookCategoryProps) {
  return (
    <div className="book-category-filter">
      <button
        type="button"
        className={`book-category-chip${selected === null ? " book-category-chip-active" : ""}`}
        onClick={() => onSelect(null)}
      >
        Todas
      </button>
      {BOOK_CATEGORIES.map((category) => (
        <button
          key={category.slug}
          type="button"
          className={`book-category-chip${selected === category.slug ? " book-category-chip-active" : ""}`}
          onClick={() => onSelect(category.slug)}
        >
          {category.icon} {category.label}
        </button>
      ))}
    </div>
  );
});
