import { useMemo, useState } from "react";
import type { BookCategory as BookCategorySlug, BookDefinition } from "../../lib/library";
import { BookCard } from "./BookCard";
import { BookCategory } from "./BookCategory";

interface BookShelfProps {
  books: BookDefinition[];
  selectedBookId: string | null;
  onSelectBook: (id: string) => void;
}

// Sprint Library System — painel esquerdo do códice: busca por título +
// filtro de categoria + a lista de livros (Etapas "Busca" e "Interface:
// Tela dividida. Lista esquerda.").
export function BookShelf({ books, selectedBookId, onSelectBook }: BookShelfProps) {
  const [query, setQuery] = useState("");
  const [category, setCategory] = useState<BookCategorySlug | null>(null);

  const filtered = useMemo(() => {
    const normalizedQuery = query.trim().toLowerCase();
    return books.filter((book) => {
      const matchesQuery = normalizedQuery === "" || book.title.toLowerCase().includes(normalizedQuery);
      const matchesCategory = category === null || book.category === category;
      return matchesQuery && matchesCategory;
    });
  }, [books, query, category]);

  return (
    <div className="book-shelf">
      <input
        type="search"
        className="book-search-input"
        value={query}
        onChange={(e) => setQuery(e.target.value)}
        placeholder="Pesquisar pelo título..."
      />
      <BookCategory selected={category} onSelect={setCategory} />
      {filtered.length === 0 ? (
        <p className="hint">Nenhum livro encontrado.</p>
      ) : (
        <div className="book-shelf-list">
          {filtered.map((book) => (
            <BookCard key={book.id} book={book} selected={book.id === selectedBookId} onSelect={onSelectBook} />
          ))}
        </div>
      )}
    </div>
  );
}
